// Pull both ensures-equalities into the proof context so z3 fires the
// extensional-equality lemma on each run independently.
assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));

// Both views are extensionally equal to the same update, so they are
// extensionally equal to each other — this gives post1_self_.seq@ == post2_self_.seq@
// and discharges det_set_equal.
assert(post1_self_.seq@ =~= post2_self_.seq@);
